export function isString(value) {
    return typeof value === "string";
}
export function isAnyString(value) {
    return typeof value === "string" || value instanceof String;
}
/**
 * Java's `hashCode` like. 32-bits hash.
 * Note: `Math.imul(..., 1)` does the same as  `| 0`, with the same speed.
 * @example
 * hashString("Lorem Ipsum") === -488052133
 * hashString("Qwerty") === -1862984904
 * hashString("A") === 65
 * hashString("👾👽💀") === -2019372252
 * @param {string} str
 * @return {number}
 */
export function hashString(str) {
    let hash = 0;
    for (let i = 0; i < str.length; i++) {
        hash = Math.imul(Math.imul(31, hash) + str.charCodeAt(i), 1);
    }
    return hash;
}
/**
 * Similar to `hashString`, but it always returns a positive number. 31-bits hash.
 * @param {string} str
 */
export function hashStringPos(str) {
    let hash = 0;
    for (let i = 0; i < str.length; i++) {
        hash = Math.imul(31, hash) + str.charCodeAt(i) & 0x7fffffff;
    }
    return hash;
}
export function downloadBlob(blob, name = "", urlOrOpts) {
    const anchor = document.createElement("a");
    anchor.setAttribute("download", name || "");
    const blobUrl = URL.createObjectURL(blob);
    let url;
    let timeout = 5000;
    if (isString(urlOrOpts)) {
        url = urlOrOpts;
    }
    else {
        url = urlOrOpts?.url;
        timeout = urlOrOpts?.timeout || timeout;
    }
    anchor.href = blobUrl + (url ? ("#" + url) : "");
    anchor.click();
    setTimeout(() => URL.revokeObjectURL(blobUrl), timeout);
}
